  ('customs-f19eb2bd-moex-00317', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '於海空搜索與救助作業中，下列何者係指在搜救區域內，負有促成搜救業務有效地予以組織化，且負責協 調搜救作業之執行單位？', '["RCC", "MCC", "SMC", "OSC"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00318', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '舵機故障的應變方式，須根據故障的原因及故障的部位，分別採取不同的應變措施。下列敘述何者正確？', '["遙控操舵台斷電時，立即切換到有緊急電源的操舵系統", "自動駕駛（autopilot）或電腦控制失效或異常時，立即切換到非從動式搖桿控制模式（non-followup mode）", "手動操舵模式失效或異常時，立即啟動另一部液壓馬達", "液壓馬達超過負荷時，立即切換至手動操舵模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00319', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '船舶擱淺所應採取的行動中，下列敘述何者錯誤？', '["主機停俥；關閉水密門；測深應予量度，以確立船舶周圍水深及海底底質", "全船所有水艙及空間都必須測量並調查船體受損情況", "任何排放或者可能洩漏的有害物質都必須向最近的海岸電台申報", "通知機艙將海水進水口關閉"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00320', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '航行中在目視範圍內發現落海的人員，下列最初應採取之行動，何者錯誤？', '["從船舷拋出附救生索之救生圈，應儘可能接近落水人員", "以船上汽笛鳴放三長聲，並高聲喊叫「人員落水」", "開始救人操船", "注意船位、風向、風速及時間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00321', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '船舶因故損壞，為避免沉沒全損而選擇故意擱淺的措施時，下列對於「船側邊故意（平行）擱淺」與「垂 直岸邊故意擱淺」兩種情況的敘述，何者錯誤？', '["垂直擱淺時之最主要脫困方法就是利用潮汐", "平行擱淺時之脫困方法只能利用調整壓艙水或貨物，千萬不能倒俥", "船舶進行平行擱淺比垂直擱淺好控制", "垂直擱淺後發生傾覆的機率較小"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00322', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '船舶進行直昇機作業時，對直昇機吊升鋼索的操作安全，下列何者錯誤？', '["吊升鋼索尾端之吊升裝備，決不可繫牢於船上任何部分或為任何固定物所牽絆", "船上人員必須主動儘早抓住下放的吊升裝備，以防強烈氣流將其擾動傷人", "為避免靜電電擊，吊升裝備的金屬部分應先接觸甲板", "吊升裝備必須遠離船舶液貨艙通氣區，以防止靜電放電引起火災或爆炸"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00323', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '以直昇機進行吊掛救援時，下列何者係單一裝備便可確實供兩人同時使用的吊掛裝備？', '["吊環", "吊籃", "吊座", "營救擔架"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00324', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '直昇機救援包括空投供應品，其各容器或包裝內之物品除應以通用語文清楚標示外，並須繫上適當顏色之 彩帶表示其內所裝物品的種類。則下列何種顏色表示毛毯及防護用衣物？', '["藍色", "黃色", "紅色", "黑色"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00325', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '下列之遇險求救裝備，何者的訊息發送頻率與EPIRB相同？', '["SART", "DSC", "ELT", "VHFCh16"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00326', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '下列之搜索模式，何者的開始搜索點基本上係在一小區域之角落，而該角落為從四方形兩邊向內量出二分 之一路徑間隔所形成者？', '["扇形搜索模式", "平行掃視搜索模式", "等高度搜索模式", "擴大式方形搜索模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
